<script>
import {onMounted,reactive,toRefs,ref} from 'vue'
import axios from 'axios'
import {useRouter} from 'vue-router'
export default {
 name:'HistoryOrderDetail',
 setup(){
    const router =useRouter()
    console.log(router)
    const orderid=router.currentRoute.value.query.orderid
    console.log(orderid)
    const isLogin =localStorage.getItem('isLogin')
    const userInfo =ref({'userInfo':{}})
    let orderdetail=reactive({'items':{}})
    let cartItems=ref(0)
    
    onMounted(() => {
        const requestdata ={'isLogin':isLogin,'orderid':orderid}
         console.log(requestdata)
        axios.post('/gethistoryorder',requestdata,{headers:{'contentType':'application/json'}}).then(
            response => {
                orderdetail.items=response.data
                console.log(orderdetail)
                cartItems.value=orderdetail.items.orderDetails.length
            
            }
        ).catch(
            error => {
                console.log(error.message)
            }
        )
        axios.get(`/userinfo?account=${isLogin}`).then(
            response =>{
                userInfo.value.userInfo=response.data
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    })


    return{
        ...toRefs(orderdetail),
        userInfo,
        cartItems
    }
 }
 
 

}
</script>

